import{_ as d,H as r,f as a,i as e}from"./chunks/framework.eFU6Tutu.js";const u=JSON.parse('{"title":"特殊音节","description":"","frontmatter":{},"headers":[],"relativePath":"guide/special-syllables.md","filePath":"guide/special-syllables.md"}'),o={name:"guide/special-syllables.md"};function h(i,t,l,n,c,s){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="特殊音节" tabindex="-1">特殊音节 <a class="header-anchor" href="#特殊音节" aria-label="Permalink to &quot;特殊音节&quot;">​</a></h1><p>大部分音节通过&quot;拆解音素 → 映射字根 → 组合成形&quot;的流水线处理。但有一些音节采用了特殊处理。</p><h2 id="零声母音节" tabindex="-1">零声母音节 <a class="header-anchor" href="#零声母音节" aria-label="Permalink to &quot;零声母音节&quot;">​</a></h2><p>零声母音节（以 <code>y</code>、<code>w</code> 开头或以元音开头）没有声母。它们的处理分为两种情况：</p><h3 id="带-⿰丨-的零声母" tabindex="-1">带 <code>⿰丨</code> 的零声母 <a class="header-anchor" href="#带-⿰丨-的零声母" aria-label="Permalink to &quot;带 `⿰丨` 的零声母&quot;">​</a></h3><p>以下零声母音节在流水线中加 <code>⿰丨</code>（丨在左，表示零声母）：</p><table tabindex="0"><thead><tr><th>拼音</th><th>音韵字</th><th>说明</th></tr></thead><tbody><tr><td>a</td><td>⿰丨八</td><td>零声母 + 八</td></tr><tr><td>o</td><td>⿰丨口</td><td>零声母 + 口</td></tr><tr><td>e</td><td>⿰丨戈</td><td>零声母 + 戈</td></tr><tr><td>ai</td><td>⿰丨才</td><td>零声母 + 才</td></tr><tr><td>ei</td><td>⿰丨巿</td><td>零声母 + 巿</td></tr><tr><td>ao</td><td>⿰丨刀</td><td>零声母 + 刀</td></tr><tr><td>ou</td><td>⿰丨口</td><td>零声母 + 口</td></tr><tr><td>wo</td><td>⿰丨火</td><td>零声母 + 火</td></tr><tr><td>ong</td><td>⿰丨工</td><td>零声母 + 工</td></tr></tbody></table><h3 id="不带-⿰丨-的零声母" tabindex="-1">不带 <code>⿰丨</code> 的零声母 <a class="header-anchor" href="#不带-⿰丨-的零声母" aria-label="Permalink to &quot;不带 `⿰丨` 的零声母&quot;">​</a></h3><p>以下零声母音节通过韵母分解流水线处理，<strong>不</strong>加 <code>⿰丨</code>：</p><table tabindex="0"><thead><tr><th>拼音</th><th>音韵字</th><th>分解</th></tr></thead><tbody><tr><td>ya</td><td>⿱一八</td><td>i_a（介音 i + 韵腹 a）</td></tr><tr><td>yao</td><td>⿱一刀</td><td>i_ao</td></tr><tr><td>you</td><td>⿱一口</td><td>i_ou</td></tr><tr><td>yan</td><td>⿵𰃦也</td><td>ie_an</td></tr><tr><td>yang</td><td>⿹勹一</td><td>i_ang</td></tr><tr><td>wa</td><td>⿱五八</td><td>u_a</td></tr><tr><td>wai</td><td>⿱五才</td><td>u_ai</td></tr><tr><td>wei</td><td>⿱五巿</td><td>u_ei</td></tr><tr><td>wan</td><td>⿵𰃦五</td><td>u_an</td></tr><tr><td>wen</td><td>⿵冂五</td><td>u_en</td></tr><tr><td>wang</td><td>⿹勹五</td><td>u_ang</td></tr></tbody></table><h2 id="直接映射音节" tabindex="-1">直接映射音节 <a class="header-anchor" href="#直接映射音节" aria-label="Permalink to &quot;直接映射音节&quot;">​</a></h2><p>以下音节不经过音素拆解，<strong>整体直接映射</strong>为一个字符：</p><table tabindex="0"><thead><tr><th>拼音</th><th>字根</th><th>说明</th></tr></thead><tbody><tr><td>yi</td><td>一</td><td>整体象形</td></tr><tr><td>wu</td><td>五</td><td>整体象形</td></tr><tr><td>yu</td><td>雨</td><td>整体象形</td></tr><tr><td>ye</td><td>也</td><td>整体象形</td></tr><tr><td>yue</td><td>月</td><td>整体象形</td></tr><tr><td>yong</td><td>用</td><td>整体象形</td></tr><tr><td>er</td><td>耳</td><td>整体象形</td></tr></tbody></table><h2 id="无声母包裹的特殊音节" tabindex="-1">无声母包裹的特殊音节 <a class="header-anchor" href="#无声母包裹的特殊音节" aria-label="Permalink to &quot;无声母包裹的特殊音节&quot;">​</a></h2><p>以下音节虽然有声母，但映射结果直接等于<strong>韵母字根</strong>（声母不包裹）：</p><table tabindex="0"><thead><tr><th>拼音</th><th>音韵字</th><th>说明</th></tr></thead><tbody><tr><td>ge</td><td>戈</td><td>直接映射为字根</td></tr><tr><td>gong</td><td>工</td><td>直接映射为字根</td></tr><tr><td>dao</td><td>刀</td><td>直接映射为字根</td></tr><tr><td>kou</td><td>口</td><td>直接映射为字根</td></tr><tr><td>huo</td><td>火</td><td>直接映射为字根</td></tr><tr><td>pei</td><td>巿</td><td>直接映射为字根</td></tr><tr><td>cai</td><td>才</td><td>直接映射为字根</td></tr></tbody></table><p>这些音节实际上在流水线之前就被 <code>getDirectSyllable</code> 直接匹配，返回韵母字根本身。</p><h2 id="独立韵尾音节" tabindex="-1">独立韵尾音节 <a class="header-anchor" href="#独立韵尾音节" aria-label="Permalink to &quot;独立韵尾音节&quot;">​</a></h2><p>以下音节只有韵尾，没有其他韵母音素，直接映射为韵尾字根（不带 <code>⿰丨</code>）：</p><table tabindex="0"><thead><tr><th>拼音</th><th>字根</th></tr></thead><tbody><tr><td>an</td><td>𰃦</td></tr><tr><td>en</td><td>冂</td></tr><tr><td>ang</td><td>勹</td></tr><tr><td>eng</td><td>𠃌</td></tr></tbody></table><hr><p>现在你已经了解了 invnz 的全部规则。前往<a href="/guide/playground.html">互动演示</a>实时体验，或查看<a href="/reference/rules.html">完整参考手册</a>。</p>',22)])])}const p=d(o,[["render",h]]);export{u as __pageData,p as default};
